import type { SearchInputConfig } from '@linm-soft/common-components';
import { salesService } from '../../services/sales/salesService';
import type { ContractDto } from '../../services/sales/models';

/** SearchInput config for sales contracts (hợp đồng) — GET /sales/contracts */
export function createContractSearchConfig(): SearchInputConfig<ContractDto> {
  return {
    api: {
      getItemKey: (c) => c.code,
      search: async ({ search, page, pageSize }) =>
        salesService.searchContracts({ search, page, pageSize }),
      getDetail: async (code) => {
        const c = await salesService.getContractByCode(code);
        if (!c) throw new Error(`Không tìm thấy hợp đồng ${code}`);
        return c;
      },
    },
    display: {
      getPrimaryDisplay: (c) => c.code,
      getSecondaryDisplay: (c) => c.customerName,
      getSingleDisplay: (c) => c.code,
    },
    columns: [
      { key: 'code', variant: 'badge', render: (c) => c.code },
      { key: 'customerName', variant: 'primary', render: (c) => c.customerName },
      {
        key: 'totalAmount',
        variant: 'meta',
        render: (c) => c.totalAmount.toLocaleString('vi-VN'),
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã HĐ' },
        { key: 'customerName', label: 'Khách hàng' },
        { key: 'totalAmount', label: 'Giá trị' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Khách hàng',
      empty: 'Không tìm thấy hợp đồng',
    },
    dropdownPortal: true,
  };
}
